```javascript
function flattenObject(obj) {
    const result = {};

    function flatten(currentObj, prefix = '') {
        for (const key in currentObj) {
            if (currentObj.hasOwnProperty(key)) {
                const newKey = prefix ? `${prefix}.${key}` : key;

                if (typeof currentObj[key] === 'object' && currentObj[key] !== null && !Array.isArray(currentObj[key])) {
                    flatten(currentObj[key], newKey);
                } else {
                    result[newKey] = currentObj[key];
                }
            }
        }
    }

    flatten(obj);
    return result;
}

const result = flattenObject({ a: { b: { c: 1 } }, d: 2, e: { f: { g: { h: 'hello' } }, i: [1, 2, 3] } });
console.log(JSON.stringify(result, null, 2));
```

Implement a JavaScript `LRUCache` class with a constructor that takes `capacity`, and methods `get(key)` and `put(key, value)`. Both operations must be O(1) time complexity. `get` returns -1 if the key doesn't exist.

Include this test code at the end:

const cache = new LRUCache(2);
cache.put(1, 1);
cache.put(2, 2);
console.log(cache.get(1));
cache.put(3, 3);
console.log(cache.get(2));
cache.put(4, 4);
console.log(cache.get(1));
console.log(cache.get(3));
console.log(cache.get(4));

```javascript
class LRUCache {
    constructor(capacity) {
        this.capacity = capacity;
        this.cache = new Map();
    }

    get(key) {
        if (!this.cache.has(key)) {
            return -1;
        }

        // Move the key to the end (most recently used)
        const value = this.cache.get(key);
        this.cache.delete(key);
        this.cache.set(key, value);

        return value;
    }

    put(key, value) {
        // If key exists, remove it first
        if (this.cache.has(key)) {
            this.cache.delete(key);
        }

        // If cache is at capacity, remove the least recently used item
        if (this.cache.size >= this.capacity) {
            const leastRecentlyUsedKey = this.cache.keys().next().value;
            this.cache.delete(leastRecentlyUsedKey);
        }

        // Add the new key-value pair
        this.cache.set(key, value);
    }
}

// Test code
const cache = new LRUCache(2);
cache.put(1, 1);
cache.put(2, 2);
console.log(cache.get(1)); // Expected: 1
cache.put(3, 3);
console.log(cache.get(2)); // Expected: -1
cache.put(4, 4);
console.log(cache.get(1)); // Expected: -1
console.log(cache.get(3)); // Expected: 3
console.log(cache.get(4)); // Expected: 4
```

```javascript
async function retry(fn, maxRetries, delayMs) {
    let lastError;

    for (let i = 0; i <= maxRetries; i++) {
        try {
            return await fn();
        } catch (error) {
            lastError = error;

            // Don't wait after the last retry
            if (i < maxRetries) {
                const delay = delayMs * Math.pow(2, i);
                await new Promise(resolve => setTimeout(resolve, delay));
            }
        }
    }

    throw lastError;
}

// Test case
async function testRetry() {
    let attemptCount = 0;

    // Async function that fails first 2 times then succeeds
    const failingFunction = async () => {
        attemptCount++;
        if (attemptCount <= 2) {
            throw new Error(`Attempt ${attemptCount} failed`);
        }
        return "Success!";
    };

    try {
        const result = await retry(failingFunction, 3, 100);
        console.log("Result:", result);
        console.log("Attempts made:", attemptCount);
    } catch (error) {
        console.log("Final error:", error.message);
        console.log("Attempts made:", attemptCount);
    }
}

// Run the test
testRetry();
```

Implement a JavaScript `EventEmitter` class with the following methods:
- `on(event, listener)` — register a listener for an event
- `off(event, listener)` — remove a specific listener
- `emit(event, ...args)` — call all listeners for an event (and wildcard '*' listeners)
- `once(event, listener)` — register a listener that fires only once

Wildcard '*' listeners receive the event name as the first argument, followed by the emitted args.

Include this test code at the end:

const emitter = new EventEmitter();
const results = [];

emitter.on('data', (val) => results.push('data:' + val));
emitter.once('data', (val) => results.push('once:' + val));
emitter.on('*', (event, val) => results.push('wild:' + event + ':' + val));

emitter.emit('data', 'first');
emitter.emit('data', 'second');
emitter.emit('other', 'third');

const handler = (val) => results.push('temp:' + val);
emitter.on('data', handler);
emitter.emit('data', 'fourth');
emitter.off('data', handler);
emitter.emit('data', 'fifth');

console.log(results.join('\n'));

```javascript
class EventEmitter {
  constructor() {
    this.events = new Map();
  }

  on(event, listener) {
    if (!this.events.has(event)) {
      this.events.set(event, []);
    }
    this.events.get(event).push(listener);
    return this;
  }

  off(event, listener) {
    if (!this.events.has(event)) {
      return this;
    }
    const listeners = this.events.get(event);
    const index = listeners.indexOf(listener);
    if (index !== -1) {
      listeners.splice(index, 1);
    }
    return this;
  }

  emit(event, ...args) {
    // Emit to specific event listeners
    if (this.events.has(event)) {
      const listeners = [...this.events.get(event)]; // Create a copy to avoid mutation during iteration
      for (const listener of listeners) {
        listener.apply(this, args);
      }
    }

    // Emit to wildcard listeners
    if (this.events.has('*')) {
      const listeners = [...this.events.get('*')]; // Create a copy to avoid mutation during iteration
      for (const listener of listeners) {
        listener.apply(this, [event, ...args]);
      }
    }

    return this;
  }

  once(event, listener) {
    const onceListener = (...args) => {
      listener.apply(this, args);
      this.off(event, onceListener);
    };
    this.on(event, onceListener);
    return this;
  }
}

// Test code
const emitter = new EventEmitter();
const results = [];

emitter.on('data', (val) => results.push('data:' + val));
emitter.once('data', (val) => results.push('once:' + val));
emitter.on('*', (event, val) => results.push('wild:' + event + ':' + val));

emitter.emit('data', 'first');
emitter.emit('data', 'second');
emitter.emit('other', 'third');

const handler = (val) => results.push('temp:' + val);
emitter.on('data', handler);
emitter.emit('data', 'fourth');
emitter.off('data', handler);
emitter.emit('data', 'fifth');

console.log(results.join('\n'));
```

