Implement a Python `@memoize` decorator that caches function results based on arguments. It should work with any combination of positional and keyword arguments.

Include this test code at the end:

@memoize
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

@memoize
def add(a, b=0):
    return a + b

print(fibonacci(10))
print(fibonacci(30))
print(add(3, b=4))
print(add(3, b=4))
print(add(1, 2))

```python
def memoize(func):
    cache = {}

    def wrapper(*args, **kwargs):
        # Create a key from arguments
        # Sort kwargs by key to ensure consistent ordering
        key = (args, tuple(sorted(kwargs.items())))

        if key in cache:
            return cache[key]

        result = func(*args, **kwargs)
        cache[key] = result
        return result

    return wrapper

@memoize
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

@memoize
def add(a, b=0):
    return a + b

print(fibonacci(10))
print(fibonacci(30))
print(add(3, b=4))
print(add(3, b=4))
print(add(1, 2))
```

```rust
use std::fmt::Display;

#[derive(Debug, Clone)]
pub struct Stack<T> {
    items: Vec<T>,
}

impl<T> Stack<T> {
    /// Create a new empty stack
    pub fn new() -> Stack<T> {
        Stack { items: Vec::new() }
    }

    /// Push an item onto the stack
    pub fn push(&mut self, item: T) {
        self.items.push(item);
    }

    /// Remove and return the top item
    pub fn pop(&mut self) -> Option<T> {
        self.items.pop()
    }

    /// Return a reference to the top item without removing it
    pub fn peek(&self) -> Option<&T> {
        self.items.last()
    }

    /// Check if the stack is empty
    pub fn is_empty(&self) -> bool {
        self.items.is_empty()
    }

    /// Return the number of elements
    pub fn len(&self) -> usize {
        self.items.len()
    }
}

impl<T: Display> Display for Stack<T> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        let mut items_str = Vec::new();
        for item in self.items.iter().rev() {
            items_str.push(format!("{}", item));
        }
        write!(f, "{}", items_str.join(" -> "))
    }
}

fn main() {
