fn validate_brackets(s: &str) -> bool {
    let mut stack = Vec::new();

    for c in s.chars() {
        match c {
            '(' | '[' | '{' => stack.push(c),
            ')' => {
                if stack.pop() != Some('(') {
                    return false;
                }
            }
            ']' => {
                if stack.pop() != Some('[') {
                    return false;
                }
            }
            '}' => {
                if stack.pop() != Some('{') {
                    return false;
                }
            }
            _ => (), // Ignore all non-bracket characters
        }
    }

    stack.is_empty()
}

fn main() {
    println!("{}", validate_brackets("()"));           // true
    println!("{}", validate_brackets("()[]{}"));       // true
    println!("{}", validate_brackets("(]"));           // false
    println!("{}", validate_brackets("([)]"));         // false
    println!("{}", validate_brackets("{[]}"));         // true
    println!("{}", validate_brackets(""));             // true
    println!("{}", validate_brackets("let x = arr[func(i)];"));  // true
    println!("{}", validate_brackets("((("));          // false
}
