```rust
#[derive(Debug, Clone)]
pub enum JsonValue {
    Null,
    Bool(bool),
    Number(f64),
    Str(String),
    Array(Vec<JsonValue>),
    Object(Vec<(String, JsonValue)>),
}

fn serialize_json(value: &JsonValue) -> String {
    match value {
        JsonValue::Null => "null".to_string(),
        JsonValue::Bool(b) => if *b { "true" } else { "false" }.to_string(),
        JsonValue::Number(n) => n.to_string(),
        JsonValue::Str(s) => {
            let mut result = String::new();
            result.push('"');
            let mut chars = s.chars().peekable();
            while let Some(ch) = chars.next() {
                match ch {
                    '"' => result.push_str("\\\""),
                    '\\' => result.push_str("\\\\"),
                    '\n' => result.push_str("\\n"),
                    '\t' => result.push_str("\\t"),
                    '\r' => result.push_str("\\r"),
                    '\u{08}' => result.push_str("\\b"),
                    '\u{0c}' => result.push_str("\\f"),
                    c if c.is_control() => {
                        // For other control characters, we'll escape them as unicode
                        let code = c as u32;
                        result.push_str(&format!("\\u{:04x}", code));
                    }
                    _ => result.push(ch),
                }
            }
            result.push('"');
            result
        },
        JsonValue::Array(arr) => {
            let elements: Vec<String> = arr.iter().map(serialize_json).collect();
            format!("[{}]", elements.join(", "))
        },
        JsonValue::Object(obj) => {
            let pairs: Vec<String> = obj.iter()
                .map(|(key, val)| format!("{}: {}", serialize_json(&JsonValue::Str(key.clone())), serialize_json(val)))
                .collect();
            format!("{{{}}}", pairs.join(", "))
        }
    }
}

fn main() {
    let value = JsonValue::Object(vec![
        ("name".to_string(), JsonValue::Str("Paloma".to_string())),
        ("version".to_string(), JsonValue::Number(2.5)),
        ("active".to_string(), JsonValue::Bool(true)),
        ("metadata".to_string(), JsonValue::Null),
        ("tags".to_string(), JsonValue::Array(vec![
            JsonValue::Str("ai".to_string()),
            JsonValue::Str("assistant".to_string()),
        ])),
        ("config".to_string(), JsonValue::Object(vec![
            ("nested".to_string(), JsonValue::Bool(true)),
            ("path".to_string(), JsonValue::Str(r"C:\Users\test".to_string())),
        ])),
    ]);

    println!("{}", serialize_json(&value));
}
