The task file is at `~/.paloma/tasks.json` with format: `[{"id": 1, "text": "...", "done": false}]`

```javascript
import { Server } from '@modelcontextprotocol/sdk/server/index.js'
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js'
import { ListToolsRequestSchema, CallToolRequestSchema } from '@modelcontextprotocol/sdk/types.js'
import fs from 'fs/promises'
import path from 'path'

const server = new Server(
  { name: 'task-manager', version: '1.0.0' },
  { capabilities: { tools: {} } }
)

// Helper function to get the tasks file path
function getTasksFilePath() {
  return path.join(process.env.HOME || process.env.USERPROFILE, '.paloma', 'tasks.json')
}

// Helper function to read tasks from file
async function readTasks() {
  try {
    const filePath = getTasksFilePath()
    const data = await fs.readFile(filePath, 'utf8')
    return JSON.parse(data)
  } catch (error) {
    // Return empty array if file doesn't exist or is invalid
    return []
  }
}

// Helper function to write tasks to file
async function writeTasks(tasks) {
  const filePath = getTasksFilePath()
  await fs.mkdir(path.dirname(filePath), { recursive: true })
  await fs.writeFile(filePath, JSON.stringify(tasks, null, 2))
}

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: 'task_list',
      description: 'List all tasks from the tasks file',
      inputSchema: {
        type: 'object',
        properties: {},
        required: []
      }
    },
    {
      name: 'task_complete',
      description: 'Mark a task as completed by ID',
      inputSchema: {
        type: 'object',
        properties: {
          id: { type: 'number', description: 'The ID of the task to complete' }
        },
        required: ['id']
      }
    }
  ]
}))

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args } = request.params

  switch (name) {
    case 'task_list': {
      const tasks = await readTasks()
      return { 
        content: [{ 
          type: 'text', 
          text: JSON.stringify(tasks, null, 2) 
        }] 
      }
    }

    case 'task_complete': {
      const { id } = args
      const tasks = await readTasks()

      // Find and update the task
      const taskIndex = tasks.findIndex(task => task.id === id)
      if (taskIndex === -1) {
        return { 
          content: [{ 
            type: 'text', 
            text: `Task with ID ${id} not found` 
          }] 
        }
      }

      // Mark task as done
      tasks[taskIndex].done = true

      // Write updated tasks back to file
      await writeTasks(tasks)

      return { 
        content: [{ 
          type: 'text', 
          text: `Task ${id} marked as completed` 
        }] 
      }
    }

    default:
      throw new Error(`Unknown tool: ${name}`)
  }
})

const transport = new StdioServerTransport()
await server.connect(transport)
```

The following Vue 3 composable has bugs in its HMR state preservation pattern. Find ALL the bugs and fix them:

```javascript
import { ref, computed, watch } from 'vue'

export function useTheme() {
  const _saved = window.__PALOMA_THEME__
  const theme = ref(_saved?.theme ?? 'dark')
  const customColors = ref(_saved?.customColors ?? {})
  const fontSize = ref(_saved?.fontSize ?? 14)

  const isDark = computed(() => theme.value === 'dark')

  if (import.meta.hot) {
    const save = () => {
      window.__PALOMA_THEME__ = {
        theme: theme.value,
        customColors: customColors.value,
        fontSize: fontSize.value
      }
    }
    watch([theme, fontSize], save)
    import.meta.hot.accept()
  }

  function setTheme(newTheme) {
    theme.value = newTheme
  }

  return { theme, isDark, customColors, fontSize, setTheme }
}
```

Looking at the code against the specified HMR state preservation pattern requirements, I can identify several deviations:

## Bugs Found:

1. **Refs not at module level** - All refs (`theme`, `customColors`, `fontSize`) are defined inside the function instead of at module level
2. **Missing _saved guard** - The `_saved` check is not guarded with `import.meta.hot ? window.__PALOMA_*__ : undefined`
3. **Incomplete watch dependencies** - The watch only includes `[theme, fontSize]` but should include ALL refs (`theme`, `customColors`, `fontSize`)
4. **Missing `{ flush: 'sync' }`** - The watch doesn't have the required flush option
5. **Missing immediate save call** - The `save()` function is not called immediately after definition

## Fixed Code:

```javascript
import { ref, computed, watch } from 'vue'

const _saved = import.meta.hot ? window.__PALOMA_THEME__ : undefined
const theme = ref(_saved?.theme ?? 'dark')
const customColors = ref(_saved?.customColors ?? {})
const fontSize = ref(_saved?.fontSize ?? 14)

export function useTheme() {
  const isDark = computed(() => theme.value === 'dark')

  if (import.meta.hot) {
    const save = () => {
      window.__PALOMA_THEME__ = {
        theme: theme.value,
        customColors: customColors.value,
        fontSize: fontSize.value
      }
    }

    // Save immediately after definition
    save()

    watch([theme, customColors, fontSize], save, { flush: 'sync' })
    import.meta.hot.accept()
  }

  function setTheme(newTheme) {
    theme.value = newTheme
  }

  return { theme, isDark, customColors, fontSize, setTheme }
}
```

