For `chat`, generate a requestId via `randomUUID()`, store the ws→requestId mapping in `cliRequestToWs`, and call `cliManager.chat({ prompt: msg.prompt, model: msg.model, sessionId: msg.sessionId })` with an event callback that sends events back to the originating ws client.

For ask_user/tool responses, look up the pending Map entry by `msg.id`, call its `resolve(msg.response)`, and delete the entry.

```javascript
// Pending request tracking
const pendingAskUser = new Map()    // id → { resolve, createdAt }
const pendingToolConfirm = new Map() // id → { resolve, createdAt }
const cliRequestToWs = new Map()    // requestId → ws

ws.on('message', (raw) => {
  let msg
  try {
    msg = JSON.parse(raw)
  } catch {
    ws.send(JSON.stringify({ type: 'error', error: 'Invalid JSON' }))
    return
  }

  switch (msg.type) {
    case 'chat': {
      const requestId = randomUUID()
      cliRequestToWs.set(requestId, ws)

      cliManager.chat({
        prompt: msg.prompt,
        model: msg.model,
        sessionId: msg.sessionId
      }, (event) => {
        // Send event back to the originating client
        const clientWs = cliRequestToWs.get(requestId)
        if (clientWs && clientWs.readyState === WebSocket.OPEN) {
          clientWs.send(JSON.stringify({
            type: 'chat_response',
            requestId,
            ...event
          }))
        }
      })
      break
    }

    case 'ask_user_response': {
      const pending = pendingAskUser.get(msg.id)
      if (pending) {
        pending.resolve(msg.response)
        pendingAskUser.delete(msg.id)
      } else {
        ws.send(JSON.stringify({ 
          type: 'error', 
          error: 'No pending ask_user request found for id: ' + msg.id 
        }))
      }
      break
    }

    case 'tool_confirm_response': {
      const pending = pendingToolConfirm.get(msg.id)
      if (pending) {
        pending.resolve(msg.response)
        pendingToolConfirm.delete(msg.id)
      } else {
        ws.send(JSON.stringify({ 
          type: 'error', 
          error: 'No pending tool_confirm request found for id: ' + msg.id 
        }))
      }
      break
    }

    default:
      ws.send(JSON.stringify({ 
        type: 'error', 
        error: 'Unknown message type: ' + msg.type 
      }))
  }
})
