```javascript
import { spawn } from 'child_process';
import { tmpdir } from 'os';
import { writeFileSync, unlinkSync } from 'fs';
import { randomUUID } from 'crypto';

class ClaudeCliManager {
  constructor(mcpProxyPort = null) {
    this.mcpProxyPort = mcpProxyPort;
    this.processes = new Map();
  }

  async chat({ prompt, model, sessionId, systemPrompt, cwd }, onEvent) {
    const requestId = randomUUID();
    const args = ['--output-format', 'stream-json', '--verbose'];

    // Handle session management
    if (sessionId) {
      args.push('--resume', sessionId);
    } else {
      sessionId = randomUUID();
      args.push('--session-id', sessionId);

      if (model) {
        args.push('--model', model);
      }

      if (systemPrompt) {
        args.push('--append-system-prompt', systemPrompt);
      }
    }

    // Handle MCP config if needed
    let mcpConfigPath = null;
    if (this.mcpProxyPort) {
      const mcpConfig = {
        mcpServers: {
          paloma: {
            type: "sse",
            url: `http://localhost:${this.mcpProxyPort}/sse`
          }
        }
      };

      mcpConfigPath = `${tmpdir()}/claude-mcp-config-${requestId}.json`;
      writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
      args.push('--mcp-config', mcpConfigPath);
      args.push('--allowedTools', 'mcp__paloma__*');
    }

    // Spawn the process
    const process = spawn('claude', args, {
      cwd,
      stdio: ['ignore', 'pipe', 'pipe']
    });

    // Handle stdout line-by-line
    let buffer = '';
    process.stdout.on('data', (data) => {
      buffer += data.toString();
      const lines = buffer.split('\n');
      buffer = lines.pop(); // Keep last incomplete line in buffer

      for (const line of lines) {
        if (line.trim()) {
          try {
            const parsed = JSON.parse(line);
            onEvent(parsed);
          } catch (e) {
            // Handle malformed JSON if needed
            console.error('Failed to parse JSON from Claude CLI:', e);
          }
        }
      }
    });

    // Handle stderr
    process.stderr.on('data', (data) => {
      console.error(`Claude CLI error: ${data}`);
    });

    // Store process info
    this.processes.set(requestId, { 
      process, 
      sessionId, 
      mcpConfigPath 
    });

    return { requestId, sessionId };
  }

  stop(requestId) {
    const procInfo = this.processes.get(requestId);
    if (!procInfo) return;

    const { process, mcpConfigPath } = procInfo;

    // Kill the process
    if (process && !process.killed) {
      process.kill('SIGTERM');
    }

    // Clean up temp file
    if (mcpConfigPath) {
      try {
        unlinkSync(mcpConfigPath);
      } catch (e) {
        console.error(`Failed to clean up MCP config file: ${e}`);
      }
    }

    // Remove from tracking map
    this.processes.delete(requestId);
  }

  cleanup() {
    for (const requestId of this.processes.keys()) {
      this.stop(requestId);
    }
  }
}

export default ClaudeCliManager;
```

